#include<bits/stdc++.h>
using namespace std;
int a[11][11];
int dp[11][11][11][11];
int main()
{
    int n;
    scanf("%d",&n);
    int x,y,z;
    while(scanf("%d%d%d",&x,&y,&z)==3&&a)
    {
        a[x][y]=z;
    }
    dp[1][1][1][1]=a[1][1];
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)if(i!=1||j!=1)
        {
            for(int x=1;x<=n;x++)
            {
                for(int y=1;y<=n;y++)if(x!=1||y!=1)
                {
                    dp[i][j][x][y]=max({dp[i-1][j][x-1][y],dp[i-1][j][x][y-1],dp[i][j-1][x-1][y],dp[i][j-1][x][y-1]})+a[i][j]+((i!=x||j!=y)?a[x][y]:0);
                }
            }
        }
    }
    printf("%d",dp[n][n][n][n]);
    return 0;
}
